INSERT OR IGNORE INTO creator_profiles (user_id, headline, long_bio, hero_image_url, niche_tags, verified, average_rating, total_sessions, starting_price_kes, active, created_at) VALUES
  ('ca000000-0000-4000-8000-000000000001','I''ll help you build a brand your customers can''t ignore','I''ve spent 8 years crafting brand strategies for Kenyan startups, NGOs, and consumer brands. From Airtel to small Nairobi barbershops — the same principles apply. Let''s make your brand unforgettable.','https://images.unsplash.com/photo-1557804506-669a67965ba0?auto=format&fit=crop&w=800&h=500&q=80','["branding","marketing","business"]',1,4.9,47,2500,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000002','Grammy-nominated producer. Your next hit starts here.','I''ve produced music for artists across East Africa and collaborated with international acts. Whether you''re a new artist or an established name looking to evolve, I''ll help you find your sound.','https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?auto=format&fit=crop&w=800&h=500&q=80','["music","production","artist-development"]',1,4.8,32,3000,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000003','Sustainable fitness for busy Kenyans — no gimmicks, just results.','After burning out chasing quick fixes myself, I became a certified personal trainer focused on sustainable, science-backed fitness. I work with corporate professionals, new moms, and athletes across Nairobi.','https://images.unsplash.com/photo-1534438327276-14e5300c3a48?auto=format&fit=crop&w=800&h=500&q=80','["fitness","wellness","nutrition"]',1,4.7,89,1500,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000004','Stop living paycheck to paycheck. Let''s build your wealth plan.','I''ve helped 200+ Kenyans navigate investment options, start SACCOs, and escape debt. I combine formal financial planning with Kenyan market realities — no textbook Western advice.','https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=800&h=500&q=80','["finance","investment","business"]',1,4.9,124,3500,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000005','I help Kenyan businesses go from invisible to irresistible online.','I built my first brand from 0 to 50K followers on a shoestring budget. Now I help businesses do the same. Specialising in Instagram, TikTok, and WhatsApp marketing for the Kenyan market.','https://images.unsplash.com/photo-1573497019940-1c28c88b4f3e?auto=format&fit=crop&w=800&h=500&q=80','["social-media","marketing","content"]',0,4.6,61,2000,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000006','From idea to funded startup — I''ve done it twice. Let me help you.','I co-founded Peza (logistics) and AfyaTech (health tech), both YC-backed. I advise early-stage founders on product-market fit, fundraising, and building teams in the African market.','https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&w=800&h=500&q=80','["tech","startups","entrepreneurship"]',1,5.0,28,5000,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000007','You''re succeeding on the outside. Let''s fix the inside too.','I coach senior professionals, entrepreneurs, and creatives who have achieved external success but feel lost or unfulfilled. My approach blends ICF-certified coaching with African values and lived experience.','https://images.unsplash.com/photo-1560250097-0b93528c311a?auto=format&fit=crop&w=800&h=500&q=80','["coaching","wellness","mindset"]',1,4.8,53,4000,1,datetime('now')),
  ('ca000000-0000-4000-8000-000000000008','I turned my YouTube channel into a 6-figure business. You can too.','I grew my YouTube channel to 200K subscribers in 2 years while working a full-time job. I now teach African creators how to build, grow, and monetise channels without selling out.','https://images.unsplash.com/photo-1611162617213-7d7a39e9b1d7?auto=format&fit=crop&w=800&h=500&q=80','["content-creation","youtube","monetisation"]',1,4.7,72,2500,1,datetime('now'));

